126→{% block scripts %}
127→<script src="/static/js/pipeline.js"></script>
128→<script>
129→// --- Status bar auto-refresh ---
130→async function refreshStatus() {
131→    try {
132→        const [authRes, statusRes] = await Promise.all([
133→            safeFetch('/api/auth/status'),
134→            safeFetch('/api/status'),
135→        ]);
136→        const auth = await authRes.json();
137→        const status = await statusRes.json();
138→
139→        const bDot = document.getElementById('browser-dot');
140→        const lDot = document.getElementById('login-dot');
141→        document.getElementById('browser-status').textContent = auth.browser_connected ? 'Connected' : 'Disconnected';
142→        bDot.dataset.ok = auth.browser_connected;
143→        document.getElementById('login-status').textContent = auth.logged_in ? 'OK' : 'No';
144→        lDot.dataset.ok = auth.logged_in;
145→        document.getElementById('queue-size').textContent = status.queue.queue_size;
146→
147→        // Status hint
148→        const hint = document.getElementById('status-hint');
149→        if (!auth.browser_connected) {
150→            hint.hidden = false;
151→            hint.className = 'status-hint-err';
152→            hint.innerHTML = '<strong>Browser 未连接</strong> — 请先启动 Chrome 调试模式：<br>' +
153→                '<code>/Applications/Google\\ Chrome.app/Contents/MacOS/Google\\ Chrome --remote-debugging-port=9222 --user-data-dir=/tmp/chrome-debug-profile</code>';
154→        } else if (!auth.logged_in) {
155→            hint.hidden = false;
156→            hint.className = 'status-hint-warn';
157→            hint.innerHTML = '<strong>未登录脉脉</strong> — 请在已启动的 Chrome 中打开 <a href="https://maimai.cn" target="_blank">maimai.cn</a> 并手动登录，登录后此状态会自动刷新。';
158→        } else {
159→            hint.hidden = true;
160→        }
161→
162→        // Update connection badge in nav
163→        const badge = document.getElementById('connection-badge');
164→        if (auth.browser_connected && auth.logged_in) {
165→            badge.textContent = 'Online';
166→            badge.dataset.status = 'ok';
167→        } else if (auth.browser_connected) {
168→            badge.textContent = 'Not Logged In';
169→            badge.dataset.status = 'warn';
170→        } else {
171→            badge.textContent = 'Offline';
172→            badge.dataset.status = 'error';
173→        }
174→    } catch (e) {
175→        console.error('Status refresh failed:', e);
176→    }
177→}
178→refreshStatus();
179→setInterval(refreshStatus, 10000);
180→
181→// --- Template loading & mode switching ---
182→(async () => {
183→    try {
184→        const res = await safeFetch('/api/templates');
185→        const templates = await res.json();
186→        const select = document.getElementById('template-select');
187→        // Append template options after the "Search only" default
188→        select.innerHTML = '<option value="">-- Search only --</option>';
189→        templates.forEach(t => {
190→            const opt = document.createElement('option');
191→            opt.value = t.name;
192→            opt.textContent = `${t.name} — ${t.description || 'No description'}`;
193→            select.appendChild(opt);
194→        });
195→
196→        function onTemplateChange() {
197→            const tpl = templates.find(t => t.name === select.value);
198→            const msgOpts = document.getElementById('messaging-options');
199→            const submitBtn = document.getElementById('submit-btn');
200→            const varsDiv = document.getElementById('template-vars');
201→
202→            if (select.value) {
203→                // Pipeline mode
204→                msgOpts.hidden = false;
205→                submitBtn.textContent = 'Start Pipeline';
206→                if (tpl && tpl.variables.length) {
207→                    const autoVars = ['name', 'company', 'position'];
208→                    const manualVars = tpl.variables.filter(v => !autoVars.includes(v));
209→                    if (manualVars.length) {
210→                        varsDiv.innerHTML = '<fieldset><legend>Template Variables</legend>' +
211→                            manualVars.map(v => {
212→                                const safe = escapeHtml(v);
213→                                return `<label>${safe}<input type="text" name="var_${safe}" placeholder="${safe}"></label>`;
214→                            }).join('') + '</fieldset>';
215→                    } else {
216→                        varsDiv.innerHTML = '<small>Variables (name, company, position) will be auto-filled per candidate.</small>';
217→                    }
218→                } else {
219→                    varsDiv.innerHTML = '';
220→                }
221→            } else {
222→                // Search-only mode
223→                msgOpts.hidden = true;
224→                submitBtn.textContent = 'Search';
225→                varsDiv.innerHTML = '';
226→            }
227→        }
228→
229→        select.addEventListener('change', onTemplateChange);
230→        onTemplateChange(); // init
231→    } catch (e) {
232→        console.error('Failed to load templates:', e);
233→    }
234→})();
235→</script>
236→{% endblock %}
