 4→
 5→function escapeHtml(str) {
 6→    if (!str) return '';
 7→    const div = document.createElement('div');
 8→    div.textContent = str;
 9→    return div.innerHTML;
10→}
11→
12→/**
13→ * Fetch wrapper with automatic res.ok check.
14→ * Extracts FastAPI error detail when available.
15→ */
16→async function safeFetch(url, options) {
17→    const res = await fetch(url, options);
18→    if (!res.ok) {
19→        let detail = res.statusText;
20→        try {
21→            const err = await res.json();
22→            detail = err.detail || err.error || detail;
23→        } catch { /* response wasn't JSON */ }
24→        throw new Error(`HTTP ${res.status}: ${detail}`);
25→    }
26→    return res;
27→}
