 88→// Global WebSocket for dashboard updates
 89→let globalWS = null;
 90→
 91→function initGlobalWS() {
 92→    globalWS = new MaimaiWS('/ws/global', {
 93→        onMessage(msg) {
 94→            // Global event handler — can be overridden per page
 95→            if (window.onGlobalWSMessage) {
 96→                window.onGlobalWSMessage(msg);
 97→            }
 98→        },
 99→    });
100→    globalWS.connect();
101→}
102→
103→/**
104→ * Connect a task-specific WebSocket.
105→ * Returns the MaimaiWS instance. Options:
106→ *   onEvent(msg)    — called for progress events
107→ *   onComplete(msg) — called when task completes
108→ *   onError(msg)    — called when task fails
109→ */
110→function connectTaskWS(taskId, options = {}) {
111→    const ws = new MaimaiWS(`/ws/task/${taskId}`, {
112→        onMessage(msg) {
113→            if (msg.event === 'completed') {
114→                if (options.onComplete) options.onComplete(msg);
115→                ws.close();
116→            } else if (msg.event === 'failed') {
117→                if (options.onError) options.onError(msg);
118→                ws.close();
119→            } else {
120→                if (options.onEvent) options.onEvent(msg);
121→            }
122→        },
123→    });
124→    ws.connect();
125→    return ws;
126→}
127→
128→// Auto-init global WS when DOM is ready
129→document.addEventListener('DOMContentLoaded', initGlobalWS);
